# Pytest Tests for HR Admin Employee Directory CSV Export

```python
"""
Tests for HR Admin Employee Directory CSV Export with PII Redaction and Webhook Emission.

Requirement:
    An hr-admin shall export the employee directory as CSV with PII redacted
    for employees who opted out of public directory. Additionally, the action
    must emit a webhook event for external consumers.
"""

import csv
import io
import json
from datetime import datetime, timezone
from unittest.mock import ANY, MagicMock, call, patch

import pytest

from myapp.exceptions import UnauthorizedError, ExportError
from myapp.models import Employee, ExportAuditLog
from myapp.services.directory_export import EmployeeDirectoryExportService
from myapp.services.webhook import WebhookService

# ---------------------------------------------------------------------------
# Constants / Shared test data
# ---------------------------------------------------------------------------

REDACTED = "[REDACTED]"

OPT_IN_EMPLOYEE = {
    "id": "emp-001",
    "name": "Alice Johnson",
    "email": "alice@example.com",
    "phone": "+1-555-100-0001",
    "department": "Engineering",
    "job_title": "Senior Engineer",
    "location": "New York",
    "opted_out_of_public_directory": False,
}

OPT_OUT_EMPLOYEE = {
    "id": "emp-002",
    "name": "Bob Smith",
    "email": "bob@example.com",
    "phone": "+1-555-100-0002",
    "department": "Finance",
    "job_title": "Analyst",
    "location": "Chicago",
    "opted_out_of_public_directory": True,
}

ANOTHER_OPT_IN_EMPLOYEE = {
    "id": "emp-003",
    "name": "Carol White",
    "email": "carol@example.com",
    "phone": "+1-555-100-0003",
    "department": "HR",
    "job_title": "HR Manager",
    "location": "Austin",
    "opted_out_of_public_directory": False,
}

PII_FIELDS = {"name", "email", "phone"}
NON_PII_FIELDS = {"id", "department", "job_title", "location"}


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------


@pytest.fixture
def hr_admin_user():
    user = MagicMock()
    user.id = "user-hr-001"
    user.role = "hr-admin"
    user.is_authenticated = True
    return user


@pytest.fixture
def non_admin_user():
    user = MagicMock()
    user.id = "user-reg-001"
    user.role = "employee"
    user.is_authenticated = True
    return user


@pytest.fixture
def unauthenticated_user():
    user = MagicMock()
    user.id = None
    user.role = None
    user.is_authenticated = False
    return user


@pytest.fixture
def mock_employee_repo():
    repo = MagicMock()
    repo.get_all.return_value = [
        Employee(**OPT_IN_EMPLOYEE),
        Employee(**OPT_OUT_EMPLOYEE),
        Employee(**ANOTHER_OPT_IN_EMPLOYEE),
    ]
    return repo


@pytest.fixture
def mock_webhook_service():
    return MagicMock(spec=WebhookService)


@pytest.fixture
def mock_audit_log():
    return MagicMock(spec=ExportAuditLog)


@pytest.fixture
def export_service(mock_employee_repo, mock_webhook_service, mock_audit_log):
    return EmployeeDirectoryExportService(
        employee_repository=mock_employee_repo,
        webhook_service=mock_webhook_service,
        audit_log=mock_audit_log,
    )


@pytest.fixture
def csv_export_result(export_service, hr_admin_user):
    """Pre-computed CSV result for reuse across multiple tests."""
    return export_service.export_csv(requested_by=hr_admin_user)


def parse_csv(csv_content: str) -> list[dict]:
    reader = csv.DictReader(io.StringIO(csv_content))
    return list(reader)


# ===========================================================================
# 1. ACCESS CONTROL
# ===========================================================================


class TestAccessControl:
    """Only hr-admin users may trigger an export."""

    def test_hr_admin_can_export(self, export_service, hr_admin_user):
        result = export_service.export_csv(requested_by=hr_admin_user)
        assert result is not None

    def test_regular_employee_cannot_export(self, export_service, non_admin_user):
        with pytest.raises(UnauthorizedError, match="hr-admin"):
            export_service.export_csv(requested_by=non_admin_user)

    def test_unauthenticated_user_cannot_export(
        self, export_service, unauthenticated_user
    ):
        with pytest.raises(UnauthorizedError):
            export_service.export_csv(requested_by=unauthenticated_user)

    def test_none_user_cannot_export(self, export_service):
        with pytest.raises((UnauthorizedError, TypeError)):
            export_service.export_csv(requested_by=None)


# ===========================================================================
# 2. CSV FORMAT & STRUCTURE
# ===========================================================================


class TestCSVFormat:
    """The exported content must be valid, well-formed CSV."""

    def test_export_returns_string(self, csv_export_result):
        assert isinstance(csv_export_result.csv_content, str)

    def test_csv_is_parseable(self, csv_export_result):
        rows = parse_csv(csv_export_result.csv_content)
        assert isinstance(rows, list)

    def test_csv_has_header_row(self, csv_export_result):
        lines = csv_export_result.csv_content.strip().splitlines()
        assert len(lines) >= 1, "CSV must contain at least a header row"

    def test_csv_contains_expected_columns(self, csv_export_result):
        rows = parse_csv(csv_export_result.csv_content)
        assert rows, "CSV must have at least one data row"
        columns = set(rows[0].keys())
        expected_columns = PII_FIELDS | NON_PII_FIELDS
        assert expected_columns.issubset(
            columns
        ), f"Missing columns: {expected_columns - columns}"

    def test_csv_row_count_matches_employee_count(
        self, csv_export_result, mock_employee_repo
    ):
        rows = parse_csv(csv_export_result.csv_content)
        expected_count = len(mock_employee_repo.get_all.return_value)
        assert len(rows) == expected_count

    def test_csv_uses_comma_delimiter(self, csv_export_result):
        first_line = csv_export_result.csv_content.splitlines()[0]
        assert "," in first_line

    def test_csv_filename_is_provided(self, csv_export_result):
        assert csv_export_result.filename
        assert csv_export_result.filename.endswith(".csv")

    def test_csv_filename_contains_timestamp(self, csv_export_result):
        # Filename should embed at least the current date for traceability
        today = datetime.now(timezone.utc).strftime("%Y%m%d")
        assert today in csv_export_result.filename

    def test_csv_content_type(self, csv_export_result):
        assert csv_export_result.content_type == "text/csv"


# ===========================================================================
# 3. PII REDACTION — OPT-OUT EMPLOYEES
# ===========================================================================


class TestPIIRedactionForOptOutEmployees:
    """PII fields must be redacted for employees who opted out."""

    @pytest.fixture(autouse=True)
    def _rows(self, csv_export_result):
        rows = parse_csv(csv_export_result.csv_content)
        self.opt_out_row = next(r for r in rows if r["id"] == OPT_OUT_EMPLOYEE["id"])

    def test_name_is_redacted(self):
        assert self.opt_out_row["name"] == REDACTED

    def test_email_is_redacted(self):
        assert self.opt_out_row["email"] == REDACTED

    def test_phone_is_redacted(self):
        assert self.opt_out_row["phone"] == REDACTED

    def test_non_pii_department_is_preserved(self):
        assert self.opt_out_row["department"] == OPT_OUT_EMPLOYEE["department"]

    def test_non_pii_job_title_is_preserved(self):
        assert self.opt_out_row["job_title"] == OPT_OUT_EMPLOYEE["job_title"]

    def test_non_pii_location_is_preserved(self):
        assert self.opt_out_row["location"] == OPT_OUT_EMPLOYEE["location"]

    def test_employee_id_is_preserved(self):
        assert self.opt_out_row["id"] == OPT_OUT_EMPLOYEE["id"]

    def test_raw_pii_value_does_not_appear_in_csv(self, csv_export_result):
        """No trace of the raw PII should exist anywhere in the CSV bytes."""
        content = csv_export_result.csv_content
        assert OPT_OUT_EMPLOYEE["name"] not in content
        assert OPT_OUT_EMPLOYEE["email"] not in content
        assert OPT_OUT_EMPLOYEE["phone"] not in content


# ===========================================================================
# 4. PII PRESERVATION — OPT-IN EMPLOYEES
# ===========================================================================


class TestPIIPreservationForOptInEmployees:
    """PII fields must be intact for employees who have NOT opted out."""

    @pytest.fixture(autouse=True)
    def _rows(self, csv_export_result):
        rows = parse_csv(csv_export_result.csv_content)
        self.opt_in_row = next(r for r in rows if r["id"] == OPT_IN_EMPLOYEE["id"])
        self.another_opt_in_row = next(
            r for r in rows if r["id"] == ANOTHER_OPT_IN_EMPLOYEE["id"]
        )

    def test_opt_in_name_is_not_redacted(self):
        assert self.opt_in_row["name"] == OPT_IN_EMPLOYEE["name"]

    def test_opt_in_email_is_not_redacted(self):
        assert self.opt_in_row["email"] == OPT_IN_EMPLOYEE["email"]

    def test_opt_in_phone_is_not_redacted(self):
        assert self.opt_in_row["phone"] == OPT_IN_EMPLOYEE["phone"]

    def test_second_opt_in_employee_name_preserved(self):
        assert self.another_opt_in_row["name"] == ANOTHER_OPT_IN_EMPLOYEE["name"]

    def test_redacted_placeholder_does_not_appear_for_opt_in(self):
        for field in PII_FIELDS:
            assert self.opt_in_row[field] != REDACTED


# ===========================================================================
# 5. EDGE CASES — MIXED / BOUNDARY DATA
# ===========================================================================


class TestEdgeCases:
    """Boundary and edge-case scenarios."""

    def test_export_with_no_employees_returns_header_only(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        mock_employee_repo.get_all.return_value = []
        result = export_service.export_csv(requested_by=hr_admin_user)
        lines = result.csv_content.strip().splitlines()
        assert len(lines) == 1, "Only the header row expected for empty directory"

    def test_export_with_all_opted_out_redacts_everyone(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        opted_out = {**OPT_IN_EMPLOYEE, "opted_out_of_public_directory": True}
        mock_employee_repo.get_all.return_value = [Employee(**opted_out)]
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        assert rows[0]["name"] == REDACTED
        assert rows[0]["email"] == REDACTED
        assert rows[0]["phone"] == REDACTED

    def test_export_with_all_opted_in_redacts_nobody(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        mock_employee_repo.get_all.return_value = [
            Employee(**OPT_IN_EMPLOYEE),
            Employee(**ANOTHER_OPT_IN_EMPLOYEE),
        ]
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        for row in rows:
            assert row["name"] != REDACTED
            assert row["email"] != REDACTED

    def test_export_handles_employee_with_null_phone(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        no_phone = {**OPT_IN_EMPLOYEE, "phone": None}
        mock_employee_repo.get_all.return_value = [Employee(**no_phone)]
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        # Should not raise; empty string or None representation acceptable
        assert rows[0]["phone"] in ("", "None", None)

    def test_export_handles_special_characters_in_name(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        special = {**OPT_IN_EMPLOYEE, "name": 'O\'Reilly, "Patrick"', "id": "emp-sc"}
        mock_employee_repo.get_all.return_value = [Employee(**special)]
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        assert rows[0]["name"] == special["name"]

    def test_export_handles_unicode_characters(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        unicode_emp = {**OPT_IN_EMPLOYEE, "name": "José García", "id": "emp-uni"}
        mock_employee_repo.get_all.return_value = [Employee(**unicode_emp)]
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        assert rows[0]["name"] == "José García"

    def test_large_directory_export_completes(
        self, export_service, hr_admin_user, mock_employee_repo
    ):
        large_list = [
            Employee(**{**OPT_IN_EMPLOYEE, "id": f"emp-{i}"}) for i in range(10_000)
        ]
        mock_employee_repo.get_all.return_value = large_list
        result = export_service.export_csv(requested_by=hr_admin_user)
        rows = parse_csv(result.csv_content)
        assert len(rows) == 10_000


# ===========================================================================
# 6. WEBHOOK EMISSION
# ===========================================================================


class TestWebhookEmission:
    """A webhook event must be emitted after every successful export."""

    def test_webhook_is_called_once_on_successful_export(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        mock_webhook_service.emit.assert_called_once()

    def test_webhook_event_type_is_correct(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        _, kwargs = mock_webhook_service.emit.call_args
        event = kwargs.get("event") or mock_webhook_service.emit.call_args.args[0]
        assert event.event_type == "hr.directory.exported"

    def test_webhook_payload_contains_exported_by(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        event = mock_webhook_service.emit.call_args.args[0]
        assert event.payload["exported_by"] == hr_admin_user.id

    def test_webhook_payload_contains_record_count(
        self, export_service, hr_admin_user, mock_webhook_service, mock_employee_repo
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        event = mock_webhook_service.emit.call_args.args[0]
        expected_count = len(mock_employee_repo.get_all.return_value)
        assert event.payload["record_count"] == expected_count

    def test_webhook_payload_contains_redacted_count(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        event = mock_webhook_service.emit.call_args.args[0]
        # Only OPT_OUT_EMPLOYEE is opted out in the default fixture
        assert event.payload["redacted_count"] == 1

    def test_webhook_payload_contains_timestamp(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        before = datetime.now(timezone.utc)
        export_service.export_csv(requested_by=hr_admin_user)
        after = datetime.now(timezone.utc)
        event = mock_webhook_service.emit.call_args.args[0]
        ts = event.payload["exported_at"]
        if isinstance(ts, str):
            ts = datetime.fromisoformat(ts)
        assert before <= ts <= after

    def test_webhook_payload_does_not_contain_pii(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        event = mock_webhook_service.emit.call_args.args[0]
        payload_str = json.dumps(event.payload)
        # Verify no raw PII from any employee leaks into the webhook payload
        for employee_data in [OPT_IN_EMPLOYEE, OPT_OUT_EMPLOYEE, ANOTHER_OPT_IN_EMPLOYEE]:
            assert employee_data["email"] not in payload_str
            assert employee_data["phone"] not in payload_str

    def test_webhook_is_not_emitted_when_export_fails(
        self, export_service, hr_admin_user, mock_webhook_service, mock_employee_repo
    ):
        mock_employee_repo.get_all.side_effect = ExportError("DB unavailable")
        with pytest.raises(ExportError):
            export_service.export_csv(requested_by=hr_admin_user)
        mock_webhook_service.emit.assert_not_called()

    def test_webhook_is_not_emitted_on_unauthorized_access(
        self, export_service, non_admin_user, mock_webhook_service
    ):
        with pytest.raises(UnauthorizedError):
            export_service.export_csv(requested_by=non_admin_user)
        mock_webhook_service.emit.assert_not_called()

    def test_webhook_emission_failure_does_not_suppress_csv_result(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        """CSV must still be returned even if the webhook delivery fails,
        but the error should be surfaced (logged / raised) to the caller."""
        mock_webhook_service.emit.side_effect = ConnectionError("Webhook endpoint down")
        # Depending on design, the service may raise or swallow; either way,
        # we verify the CSV content itself was produced before the webhook call.
        with pytest.raises(ConnectionError):
            result = export_service.export_csv(requested_by=hr_admin_user)
        # If design chooses to swallow and log instead, assert result is valid CSV:
        # rows = parse_csv(result.csv_content)
        # assert len(rows) > 0

    def test_webhook_contains_export_filename(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        result = export_service.export_csv(requested_by=hr_admin_user)
        event = mock_webhook_service.emit.call_args.args[0]
        assert event.payload.get("filename") == result.filename


# ===========================================================================
# 7. AUDIT LOGGING
# ===========================================================================


class TestAuditLogging:
    """Every export attempt (success or failure) must be audit-logged."""

    def test_audit_log_written_on_successful_export(
        self, export_service, hr_admin_user, mock_audit_log
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        mock_audit_log.record.assert_called_once()

    def test_audit_log_contains_actor(
        self, export_service, hr_admin_user, mock_audit_log
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        log_entry = mock_audit_log.record.call_args.kwargs
        assert log_entry.get("actor_id") == hr_admin_user.id

    def test_audit_log_contains_action_type(
        self, export_service, hr_admin_user, mock_audit_log
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        log_entry = mock_audit_log.record.call_args.kwargs
        assert log_entry.get("action") == "EXPORT_EMPLOYEE_DIRECTORY_CSV"

    def test_audit_log_records_unauthorized_attempt(
        self, export_service, non_admin_user, mock_audit_log
    ):
        with pytest.raises(UnauthorizedError):
            export_service.export_csv(requested_by=non_admin_user)
        mock_audit_log.record.assert_called_once()
        log_entry = mock_audit_log.record.call_args.kwargs
        assert log_entry.get("outcome") == "UNAUTHORIZED"


# ===========================================================================
# 8. IDEMPOTENCY / REPEATED EXPORTS
# ===========================================================================


class TestRepeatedExports:
    """Calling export multiple times must be safe and consistent."""

    def test_two_consecutive_exports_both_succeed(
        self, export_service, hr_admin_user
    ):
        result1 = export_service.export_csv(requested_by=hr_admin_user)
        result2 = export_service.export_csv(requested_by=hr_admin_user)
        assert result1.csv_content == result2.csv_content

    def test_webhook_emitted_for_each_export(
        self, export_service, hr_admin_user, mock_webhook_service
    ):
        export_service.export_csv(requested_by=hr_admin_user)
        export_service.export_csv(requested_by=hr_admin_user)
        assert mock_webhook_service.emit.call_count == 2
```

---

## Key Design Decisions & Notes

| Area | Decision |
|---|---|
| **Access control** | Tests assert `UnauthorizedError` for non-admin and unauthenticated roles |
| **PII redaction** | Asserts placeholder `[REDACTED]` on all three PII fields for opt-out employees **and** confirms the raw values are absent from the entire CSV string |
| **Non-PII preservation** | Confirms `department`, `job_title`, `location`, and `id` are never redacted |
| **Webhook payload** | Validates `event_type`, `exported_by`, `record_count`, `redacted_count`, `exported_at`, `filename`, and absence of PII |
| **Failure cases** | Webhook must not fire on auth failure or repository error; CSV should not silently hide webhook delivery failures |
| **Audit log** | Every invocation (including unauthorized attempts) must produce an audit record |
| **Edge cases** | Empty directory, all opted-out, all opted-in, null fields, special chars, unicode, large datasets |
